#!/usr/bin/env node

/**
 * AI-Powered Smart Agent with LLM Validation
 * 
 * This is a SMART AGENT that:
 * 1. Registers itself by solving challenges from other smart agents
 * 2. Receives an API key generated by 3 validator smart agents
 * 3. Then acts as a validator using LLM to generate dynamic challenges
 * 
 * Usage:
 *   node ai-validator-agent.js \
 *     --name SmartAI \
 *     --openai-url https://api.openai.com/v1 \
 *     --model gpt-4 \
 *     --api-key sk-...
 */

import Gun from 'gun';
import 'gun/sea.js';
import 'gun/lib/radix.js';
import 'gun/lib/radisk.js';
import 'gun/lib/store.js';
import 'gun/lib/rindexed.js';
import { RegistrationManager } from './registration-manager.js';
import { getRandomChallenge } from './challenge-bank.js';

// LLM Client for generating challenges
class LLMClient {
    constructor(apiUrl, apiKey, model = 'gpt-4') {
        this.apiUrl = apiUrl || 'https://api.openai.com/v1';
        this.apiKey = apiKey;
        this.model = model;
    }

    async generateChallenge(difficulty = 'medium') {
        const prompt = `Generate a unique proof-of-intelligence challenge for an AI agent registration system.

Requirements:
- Difficulty: ${difficulty}
- Question must be solvable by an intelligent agent
- Include a clear, unambiguous answer (one word or short phrase)
- Challenge types: math, logic, pattern recognition, word puzzles, or code comprehension

Return ONLY valid JSON with this structure:
{
  "question": "your challenge question",
  "answer": "correct answer",
  "type": "math|logic|pattern|code|word",
  "difficulty": "${difficulty}"
}

Be creative and avoid common questions. The question should test intelligence, not memorization.`;

        try {
            const requestBody = {
                model: this.model,
                messages: [
                    {
                        role: 'system',
                        content: 'You are a JSON generator. You MUST respond with ONLY valid JSON. No explanations, no markdown, no additional text.'
                    },
                    {
                        role: 'user',
                        content: prompt
                    }
                ],
                temperature: 0.7,
                max_tokens: 300
            };
            
            // Try to use JSON mode if API supports it (OpenAI-compatible)
            try {
                requestBody.response_format = { type: 'json_object' };
            } catch (e) {
                // API might not support response_format, ignore
            }
            
            const response = await fetch(`${this.apiUrl}/chat/completions`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${this.apiKey}`
                },
                body: JSON.stringify(requestBody)
            });

            if (!response.ok) {
                const errorText = await response.text();
                console.error(`   API Response Status: ${response.status}`);
                console.error(`   API Response Body: ${errorText}`);
                throw new Error(`LLM API error: ${response.statusText}`);
            }

            const data = await response.json();
            const content = data.choices[0].message.content.trim();
            
            // Try to extract JSON from the response
            let jsonStr = content;
            
            // Remove markdown code blocks
            jsonStr = jsonStr.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
            
            // Try to find JSON object in the text (in case LLM added explanation)
            const jsonMatch = jsonStr.match(/\{[\s\S]*\}/);
            if (jsonMatch) {
                jsonStr = jsonMatch[0];
            }
            
            const parsed = JSON.parse(jsonStr);
            
            // Validate required fields
            if (!parsed.question || !parsed.answer || !parsed.type) {
                throw new Error('Missing required fields in generated challenge');
            }
            
            return parsed;
        } catch (error) {
            console.error('❌ Failed to generate challenge:', error.message);
            if (error.message.includes('Unexpected token')) {
                console.error('   LLM returned non-JSON response. Using fallback challenge.');
            }
            
            // Fallback to hardcoded challenges (rotate through different types)
            const fallbacks = [
                { question: 'What is 7 + 8?', answer: '15', type: 'math', difficulty: 'easy' },
                { question: 'What comes next in the sequence: 2, 4, 8, 16, ?', answer: '32', type: 'pattern', difficulty: 'medium' },
                { question: 'If all roses are flowers and some flowers fade quickly, can we conclude that some roses fade quickly?', answer: 'no', type: 'logic', difficulty: 'medium' }
            ];
            
            return fallbacks[Math.floor(Math.random() * fallbacks.length)];
        }
    }

    async solveChallenge(question, type) {
        const prompt = `Solve this challenge:

Type: ${type}
Question: ${question}

Provide ONLY the answer - no explanation, no extra text. Just the answer.`;

        try {
            const response = await fetch(`${this.apiUrl}/chat/completions`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${this.apiKey}`
                },
                body: JSON.stringify({
                    model: this.model,
                    messages: [
                        {
                            role: 'system',
                            content: 'You solve puzzles and challenges. Provide only the answer, no explanation.'
                        },
                        {
                            role: 'user',
                            content: prompt
                        }
                    ],
                    temperature: 0.3, // Low temperature for accuracy
                    max_tokens: 50
                })
            });

            if (!response.ok) {
                throw new Error(`LLM API error: ${response.statusText}`);
            }

            const data = await response.json();
            return data.choices[0].message.content.trim();
        } catch (error) {
            console.error('❌ Failed to solve challenge:', error.message);
            return null;
        }
    }

    async testConnection() {
        try {
            const response = await fetch(`${this.apiUrl}/models`, {
                headers: {
                    'Authorization': `Bearer ${this.apiKey}`
                }
            });
            return response.ok;
        } catch (error) {
            return false;
        }
    }
}

// AI-Powered Challenge Generator with Static Challenge Bank
class AIPeerChallenge {
    constructor(llmClient, useLLMMode = false) {
        this.llm = llmClient;
        this.useLLMMode = useLLMMode; // Flag to toggle between static and LLM-generated challenges
        console.log(`🎯 Challenge Mode: ${useLLMMode ? 'LLM-Generated (Dynamic)' : 'Static Bank (500 preloaded)'}`);  
    }

    async generate() {
        // Use static challenge bank by default (no API calls, no rate limits)
        if (!this.useLLMMode) {
            const challenge = getRandomChallenge();
            return {
                type: challenge.type,
                question: challenge.question,
                answer: challenge.answer
            };
        }
        
        // LLM mode: Generate dynamic challenges (may hit rate limits)
        console.log('🤖 Generating LLM challenge...');
        const challenge = await this.llm.generateChallenge('medium');
        return {
            type: challenge.type,
            question: challenge.question,
            answer: challenge.answer
        };
    }

    async solve(challenge) {
        // Always use LLM to solve challenges
        return await this.llm.solveChallenge(challenge.question, challenge.type);
    }

    async verify(challenge, solution) {
        const normalized = (str) => String(str || '').toLowerCase().trim();
        return normalized(solution) === normalized(challenge.answer);
    }
}

// Smart AI Agent (Registers itself, then validates others)
class SmartAIAgent {
    constructor(name, llmClient, relayUrl, useLLMMode = false) {
        this.name = name;
        this.llm = llmClient;
        this.relayUrl = relayUrl;
        this.useLLMMode = useLLMMode; // Toggle between static and LLM-generated challenges
        this.keypair = null;
        this.gun = null;
        this.db = null;
        this.apiKey = null;
        this.aiChallenge = null;
    }

    async initialize() {
        console.log(`\n🤖 Smart AI Agent: ${this.name}`);
        console.log(`🔗 Relay: ${this.relayUrl}`);
        
        // Generate keypair
        this.keypair = await Gun.SEA.pair();
        console.log(`🔑 Public Key: ${this.keypair.pub.substring(0, 20)}...`);

        // Create AI challenge generator with mode setting
        this.aiChallenge = new AIPeerChallenge(this.llm, this.useLLMMode);

        // Check for master validator key first (highest priority)
        const masterKey = process.env.VALIDATOR_MASTER_KEY || process.env.RELAY_API_KEY;
        if (masterKey) {
            console.log(`✅ Using validator master key (${masterKey.substring(0, 8)}...${masterKey.substring(masterKey.length - 4)})`);
            this.apiKey = masterKey;
        } else {
            // Check if already registered
            const regManager = new RegistrationManager(this.name, this.keypair, this.relayUrl);
            
            if (regManager.hasStoredKey()) {
                console.log(`✅ Found existing API key`);
                this.apiKey = regManager.loadStoredKey();
            } else {
                console.log(`\n🔐 No API key found - Starting registration as SMART AGENT...`);
                console.log(`📝 Will solve challenges from other smart agents\n`);
                
                // Initialize Gun with demo key for registration
                this.gun = Gun({
                    peers: [`${this.relayUrl}/gun?key=demo-registration`],
                    radisk: false
                });
                this.db = this.gun.get('agentworkbook-v1');

                // Register using AI challenge solver
                try {
                    this.apiKey = await regManager.register(this.gun, this.db, this.aiChallenge);
                    console.log(`\n✅ Registration complete! API key: ${this.apiKey.substring(0, 20)}...`);
                } catch (error) {
                    console.error(`❌ Registration failed:`, error.message);
                    process.exit(1);
                }
            }
        }

        // Now connect with real API key
        this.gun = Gun({
            peers: [`${this.relayUrl}/gun?key=${this.apiKey}`],
            radisk: true,
            file: `radata-${this.name}`
        });
        this.db = this.gun.get('agentworkbook-v1');

        console.log(`✅ Smart agent initialized with API key\n`);
    }

    async start() {
        // Test relay connection before starting
        console.log(`🔌 Testing connection to relay: ${this.relayUrl}...`);
        
        try {
            const response = await fetch(`${this.relayUrl}/health`, {
                method: 'GET',
                timeout: 10000
            });
            
            if (!response.ok) {
                throw new Error(`Relay returned status ${response.status}`);
            }
            
            console.log(`✅ Relay connection successful\n`);
        } catch (error) {
            console.error(`❌ CANNOT CONNECT TO RELAY: ${this.relayUrl}`);
            console.error(`   Error: ${error.message}`);
            console.error(`\n🛑 Validator will not start without relay connection`);
            console.error(`   Please check if the relay server is running:\n`);
            console.error(`   ${this.relayUrl}/health\n`);
            process.exit(1);
        }

        // Send initial heartbeat to register as active validator
        await this.sendHeartbeat();

        console.log(`👁️  Now acting as AI validator for new registrations...\n`);

        // Create separate Gun connection for monitoring registrations
        // Agents register on demo-registration channel, validators must listen there
        // axe: false — disable multicast so all traffic goes through the relay WebSocket
        const registrationGun = Gun({
            peers: [`${this.relayUrl}/gun?key=demo-registration`],
            radisk: false,
            axe: false
        });
        const registrationDb = registrationGun.get('agentworkbook-v1');

        console.log(`📡 Listening for registrations on shared channel: demo-registration\n`);

        // Use existing validator pattern but with AI challenges
        // Listen on the shared registration channel
        const validatorIP = process.env.VALIDATOR_IP || 'auto-detect';
        await RegistrationManager.actAsValidator(
            registrationGun,
            registrationDb,
            this.name,
            this.keypair,
            validatorIP,
            this.aiChallenge  // Pass AI challenge generator instead of hardcoded
        );

        // Publish heartbeat to Gun.js and relay server
        setInterval(() => {
            this.db.get('agents').get(this.name).put({
                name: this.name,
                role: 'smart-validator',
                type: 'ai-powered',
                pub: this.keypair.pub,
                lastSeen: Date.now()
            });
            // Also send heartbeat to relay to track active validators
            this.sendHeartbeat().catch(err => console.error(`Heartbeat failed: ${err.message}`));
        }, 60000);

        console.log(`🚀 Validator running\n`);
    }

    async sendHeartbeat() {
        try {
            const response = await fetch(`${this.relayUrl}/validator/heartbeat`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'X-API-Key': this.apiKey
                },
                body: JSON.stringify({
                    name: this.name,
                    timestamp: Date.now()
                })
            });

            if (!response.ok) {
                console.error(`❌ Heartbeat failed: ${response.status} ${response.statusText}`);
                return;
            }

            const result = await response.json();
            console.log(`💓 Heartbeat sent - ${result.activeValidators} validators online`);
        } catch (error) {
            console.error(`❌ Heartbeat error: ${error.message}`);
        }
    }
}

// CLI Argument Parsing
function parseArgs() {
    const args = process.argv.slice(2);
    const config = {
        name: 'SmartAI',
        openaiUrl: process.env.OPENAI_API_URL || 'https://api.openai.com/v1',
        model: process.env.OPENAI_MODEL || 'gpt-4',
        apiKey: process.env.OPENAI_API_KEY,
        relayUrl: process.env.RELAY_URL || 'https://vishalmysore-agentworkbookrelayserver.hf.space',
        useLLMMode: false // Default: use static challenge bank
    };

    for (let i = 0; i < args.length; i++) {
        switch (args[i]) {
            case '--name':
                config.name = args[++i];
                break;
            case '--openai-url':
                config.openaiUrl = args[++i];
                break;
            case '--model':
                config.model = args[++i];
                break;
            case '--api-key':
                config.apiKey = args[++i];
                break;
            case '--relay-url':
                config.relayUrl = args[++i];
                break;
            case '--llm-mode':
                config.useLLMMode = true;
                console.log('🤖 LLM Mode ENABLED: Will generate dynamic challenges using LLM');
                break;
            case '--help':
                console.log(`
Smart AI Agent - Self-Registering Validator with LLM

This is a SMART AGENT that:
1. Registers itself by solving challenges from other smart agents
2. Receives API key from 3 validators  
3. Acts as validator using challenges (static bank by default)

Usage:
  node ai-validator-agent.js [options]

Options:
  --name <name>           Agent name (default: SmartAI)
  --openai-url <url>      OpenAI API URL (default: https://api.openai.com/v1)
  --model <model>         LLM model (default: gpt-4)
  --api-key <key>         OpenAI API key (or env: OPENAI_API_KEY)
  --relay-url <url>       Gun.js relay URL (or env: RELAY_URL)
  --llm-mode              Use LLM for dynamic challenge generation (default: static bank)
  --help                  Show this help

Environment Variables:
  OPENAI_API_URL          OpenAI API endpoint
  OPENAI_MODEL            Model name (gpt-4, gpt-3.5-turbo, etc.)
  OPENAI_API_KEY          OpenAI API key
  RELAY_URL               Gun.js relay server URL

Challenge Modes:
  Default (Static Bank):  Uses 500 pre-loaded complex questions
                         - No API calls, no rate limits
                         - Instant response
                         - Questions designed for AI agents
  
  LLM Mode (--llm-mode): Generates dynamic challenges using LLM
                         - Unique questions every time
                         - May hit rate limits
                         - Requires API credits

Examples:
  # Basic usage with static challenges (recommended, no rate limits)
  node ai-validator-agent.js --name SmartAI1 --api-key sk-...

  # With LLM-generated dynamic challenges
  node ai-validator-agent.js --name SmartAI1 --api-key sk-... --llm-mode

  # NVIDIA Nemotron with static challenges
  node ai-validator-agent.js \\
    --name NVIDIAAgent \\
    --openai-url https://integrate.api.nvidia.com/v1 \\
    --model nvidia/nemotron-nano-12b-v2-vl \\
    --api-key nvapi-...

  # Ollama (local, free)
  node ai-validator-agent.js \\
    --name LocalAI \\
    --openai-url http://localhost:11434/v1 \\
    --model llama2 \\
    --api-key ollama
`);
                process.exit(0);
        }
    }

    return config;
}

// Main
async function main() {
    console.log('╔══════════════════════════════════════════════╗');
    console.log('║   Smart AI Agent - LLM-Powered Validator    ║');
    console.log('║   Self-Registers + Validates Others         ║');
    console.log('╚══════════════════════════════════════════════╝\n');

    const config = parseArgs();

    // Validate required config
    if (!config.apiKey) {
        console.error('❌ Error: OpenAI API key required');
        console.error('   Provide via --api-key or OPENAI_API_KEY environment variable\n');
        process.exit(1);
    }

    // Initialize LLM client
    console.log('🧪 Testing LLM connection...');
    const llm = new LLMClient(config.openaiUrl, config.apiKey, config.model);
    
    const isConnected = await llm.testConnection();
    if (!isConnected) {
        console.warn('⚠️  Warning: Could not verify LLM connection');
        console.warn('   Will attempt to use anyway...\n');
    } else {
        console.log('✅ LLM connection verified\n');
    }

    // Only test challenge generation in LLM mode (avoid unnecessary API calls)
    if (config.useLLMMode) {
        console.log('🎯 Testing LLM challenge generation...');
        const testChallenge = await llm.generateChallenge('easy');
        console.log(`   Question: ${testChallenge.question}`);
        console.log(`   Type: ${testChallenge.type}`);
        console.log(`   (Answer: ${testChallenge.answer})`);
        console.log('✅ Challenge generation working!\n');
    } else {
        console.log('📦 Using static challenge bank (500 preloaded questions)');
        console.log('   ⚡ No API calls for challenges = No rate limits\n');
    }

    // Initialize smart agent
    const agent = new SmartAIAgent(
        config.name,
        llm,
        config.relayUrl,
        config.useLLMMode  // Pass LLM mode flag
    );

    await agent.initialize();
    await agent.start();

    // Keep alive
    console.log('═'.repeat(50));
    console.log('\n💡 Press Ctrl+C to stop.\n');
}

// Run
main().catch(error => {
    console.error('💥 Fatal error:', error);
    process.exit(1);
});
